import{j as o,b as t,c as s,a9 as e}from"./chunks/framework.CFGK5tmi.js";const p="/assets/WkTEQUGFjPWhW4hiK7PVBZ.Ba7BBSGD.png",c="/assets/%E6%B5%8F%E8%A7%88%E5%99%A8%E6%9C%8D%E5%8A%A1%E5%99%A8%E4%BA%A4%E4%BA%92.Ce5pAUSp.jpg",r="/assets/url%E7%BB%84%E6%88%90.Butmlozp.jpg",l="/assets/%E8%AF%B7%E6%B1%82%E6%8A%A5%E6%96%87%E5%92%8C%E5%93%8D%E5%BA%94%E6%8A%A5%E6%96%87.DqTvNqj8.jpg",a="/assets/DNS%E7%AD%89%E7%BA%A7.DbjpPne9.jpg",i="/assets/%E5%9F%9F%E5%90%8D%E7%9A%84%E8%A7%A3%E6%9E%90%E6%B5%81%E7%A8%8B.D0BFWSYt.jpg",n="/assets/%E5%8D%8F%E8%AE%AE%E6%A0%88.DeDHRkZ2.jpg",d="/assets/TCP%E5%8D%8F%E8%AE%AE%E6%8A%A5%E6%96%87.T_pnoQ6G.jpg",g="/assets/TCP%E4%B8%89%E6%AC%A1%E6%8F%A1%E6%89%8B.drawio.ROeA9YUA.png",P="/assets/TCP%E7%8A%B6%E6%80%81.602zXx_1.jpg",A="/assets/TCP%E5%88%86%E6%AE%B5.BjA5MDEL.jpg",u="/assets/12.CKYOFZKS.jpg",C="/assets/13.6I7b_HQH.jpg",_="/assets/14.BpsqDyse.jpg",m="/assets/15.LLdLXeH6.jpg",T="/assets/16.CykYj6Vn.jpg",b="/assets/17.G7x2toB9.jpg",h="/assets/18.4mh38CQ8.jpg",E="/assets/19.BgkpllGl.jpg",k="/assets/20.93XOjQxR.jpg",M="/assets/21.DBVyO0LX.jpg",q="/assets/%E6%95%B0%E6%8D%AE%E5%8C%85.drawio.DIR3zk7U.png",I="/assets/23.CpB5qdL3.jpg",S="/assets/24.D2kWEY52.jpg",w=JSON.parse('{"title":"输入url到展示网页发生了什么","description":"","frontmatter":{},"headers":[],"relativePath":"csbase/network/输入url到展示网页发生了什么.md","filePath":"csbase/network/输入url到展示网页发生了什么.md","lastUpdated":null}'),D={name:"csbase/network/输入url到展示网页发生了什么.md"},B=e('<h1 id="输入url到展示网页发生了什么" tabindex="-1">输入url到展示网页发生了什么 <a class="header-anchor" href="#输入url到展示网页发生了什么" aria-label="Permalink to &quot;输入url到展示网页发生了什么&quot;">​</a></h1><p>时序图：</p><p><img src="'+p+'" alt="从输入URL到浏览器展示网页的过程"></p><p>说明图：<img src="'+c+'" alt="简单的网络模型"></p><h2 id="http" tabindex="-1">HTTP <a class="header-anchor" href="#http" aria-label="Permalink to &quot;HTTP&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>浏览器首先需要解析URL，从而生成要发送给服务器的请求消息。</p></div><p><img src="'+r+'" alt="URL 解析"></p><p>对<code>url</code>进行解析之后，浏览器就确定了web服务器和文件名，接下来就根据这些信息生成HTTP请求了。HTTP请求信息如下：</p><p><img src="'+l+'" alt="HTTP 的消息格式"></p><h2 id="dns" tabindex="-1">DNS <a class="header-anchor" href="#dns" aria-label="Permalink to &quot;DNS&quot;">​</a></h2><p>在解析完url并生成请求报文之后，还需要使用DNS服务器来查询域名对应的ip地址。有一种服务器就专门保存了 <code>Web</code> 服务器域名与 <code>IP</code> 的对应关系，它就是 <code>DNS</code> 服务器。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>域名的层级关系</p></div><p>DNS 中的域名都是用<strong>句点</strong>来分隔的，比如 <code>www.server.com</code>，这里的句点代表了不同层次之间的<strong>界限</strong>。在域名中，越靠右边，表示其等级越高。实际上域名最后还有一个点，比如 <code>www.server.com.</code>，这个最后的一个点代表根域名。也就是，<code>.</code> 根域是在最顶层，它的下一层就是 <code>.com</code> 顶级域，再下面是 <code>server.com</code>。</p><p><img src="'+a+'" alt="DNS 树状结构"></p><p>因此，客户端只要能够找到任意一台 DNS 服务器，就可以通过它找到根域 DNS 服务器，然后再一路顺藤摸瓜找到位于下层的某台目标 DNS 服务器。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>域名的解析流程</p></div><p><img src="'+i+'" alt="域名解析的工作流程"></p><p>注意，浏览器首先是回访问本地的缓存的，当本地缓存中没有记录，才会开始去问「本地 DNS 服务器」。</p><h2 id="协议栈" tabindex="-1">协议栈 <a class="header-anchor" href="#协议栈" aria-label="Permalink to &quot;协议栈&quot;">​</a></h2><p>通过 DNS 获取到 IP 后，就可以把 HTTP 的传输工作交给操作系统中的<strong>协议栈</strong>。</p><p>应用程序是通过调用<code>Socket</code>库来委托协议栈工作的，在Socket被成功创建并配置后，应用程序就可以通过它发送HTTP请求了。当应用程序调用发送函数时，请求数据会被推送到协议栈中。</p><p>协议栈在接收到数据后，会按照TCP/IP协议进行层层封装，加上必要的协议头，形成一个完整的网络数据包。然后，这个数据包会被发送到网络接口卡（NIC），进而被传输到网络上。</p><p>在数据包经过网络传输到达目标服务器后，服务器的协议栈会进行相反的操作，即层层解封装，提取出真正的HTTP请求数据，然后将其交给服务器上的相应应用程序处理。</p><p>这样，通过Socket库和协议栈的协作，应用程序就能够实现与网络上的其他主机进行HTTP通信了。整个过程对应用程序来说是透明的，它只需要关注于发送和接收的数据内容，而不需要关心底层的网络通信细节。</p><p><img src="'+n+'" alt="img"></p><h2 id="tcp" tabindex="-1">TCP <a class="header-anchor" href="#tcp" aria-label="Permalink to &quot;TCP&quot;">​</a></h2><p>HTTP协议是基于TCP协议的，TCP协议的报文如下：</p><p><img src="'+d+'" alt="TCP 包头格式"></p><ul><li><strong>端口号</strong>是为了确认发给哪个应用</li><li><strong>序号</strong>是为了解决包的乱序问题</li><li><strong>确认号</strong>是为了确认对方有没有收到，用于解决丢包的问题</li><li><strong>状态位</strong>，例如例<code>SYN</code> 是发起一个连接，<code>ACK</code> 是回复，<code>RST</code> 是重新连接，<code>FIN</code> 是结束连接等。</li><li><strong>窗口大小</strong>是双方各声明一个窗口大小(缓存)用来标识自己的处理能力。<strong>窗口大小代表了发送端在不需要等待确认的情况下可以连续发送的数据量</strong>。</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>TCP 传输数据之前，要先三次握手建立连接</p></div><p>在 HTTP 传输数据之前，首先需要 TCP 建立连接，TCP 连接的建立，通常称为<strong>三次握手</strong>。</p><ul><li>一开始，客户端和服务端都处于 <code>CLOSED</code> 状态。先是服务端主动监听某个端口，处于 <code>LISTEN</code> 状态。</li><li>然后客户端主动发起连接 <code>SYN</code>，之后处于 <code>SYN-SENT</code> 状态。</li><li>服务端收到发起的连接，返回 <code>SYN</code>，并且 <code>ACK</code> 客户端的 <code>SYN</code>，之后处于 <code>SYN-RCVD</code> 状态。</li><li>客户端收到服务端发送的 <code>SYN</code> 和 <code>ACK</code> 之后，发送对 <code>SYN</code> 确认的 <code>ACK</code>，之后处于 <code>ESTABLISHED</code> 状态，因为它一发一收成功了。</li><li>服务端收到 <code>ACK</code> 的 <code>ACK</code> 之后，处于 <code>ESTABLISHED</code> 状态，因为它也一发一收了。</li></ul><p>三次握手目的是<strong>保证双方都有发送和接收的能力</strong>。</p><p><img src="'+g+'" alt="TCP 三次握手"></p><p>在 Linux 可以通过 <code>netstat -napt</code> 命令查看。</p><p><img src="'+P+'" alt="TCP 连接状态查看"></p><blockquote><p>TCP 分割数据</p></blockquote><p>如果 HTTP 请求消息比较长，超过了 <code>MSS</code> 的长度，这时 TCP 就需要把 HTTP 的数据拆解成一块块的数据发送，而不是一次性发送所有数据。</p><p><img src="'+A+'" alt="MTU 与 MSS"></p><ul><li><code>MTU</code>：一个网络包的最大长度，以太网中一般为 <code>1500</code> 字节。</li><li><code>MSS</code>：除去 IP 和 TCP 头部之后，一个网络包所能容纳的 TCP 数据的最大长度。</li></ul><p><img src="'+u+'" alt="数据包分割"></p><blockquote><p>TCP报文生成</p></blockquote><p><img src="'+C+'" alt="TCP 层报文"></p><h2 id="ip" tabindex="-1">IP <a class="header-anchor" href="#ip" aria-label="Permalink to &quot;IP&quot;">​</a></h2><p>TCP 模块在执行连接、收发、断开等各阶段操作时，都需要委托 IP 模块将数据封装成<strong>网络包</strong>发送给通信对象。</p><blockquote><p>IP包的头格式</p></blockquote><p><img src="'+_+'" alt="IP 包头格式"></p><p>在 IP 协议里面需要有<strong>源地址 IP</strong> 和 <strong>目标地址 IP</strong>：</p><ul><li>源地址IP，即是客户端输出的 IP 地址；</li><li>目标地址，即通过 DNS 域名解析得到的 Web 服务器 IP。</li></ul><p>因为 HTTP 是经过 TCP 传输的，所以在 IP 包头的<strong>协议号</strong>，要填写为 <code>06</code>（十六进制），表示协议为 TCP。</p><blockquote><p>假设客户端有多个网卡，就会有多个 IP 地址，那 IP 头部的源地址应该选择哪个 IP 呢？</p></blockquote><p>当存在多个网卡时，在填写源地址 IP 时，就需要判断到底应该填写哪个地址。这个判断相当于在多块网卡中判断应该使用哪个一块网卡来发送包。此时我们需要查看<strong>路由表</strong>，来判断根据哪一个网卡作为源地址。</p><p>在 Linux 操作系统，我们可以使用 <code>route -n</code> 命令查看当前系统的路由表。</p><p><img src="'+m+'" alt="路由表"></p><p>举个例子，根据上面的路由表，我们假设 Web 服务器的<strong>目标地址</strong>是 <code>192.168.10.200</code>。</p><p><img src="'+T+'" alt="路由规则判断"></p><p>第三条目比较特殊，它目标地址和子网掩码都是 <code>0.0.0.0</code>，这表示<strong>默认网关</strong>，如果其他所有条目都无法匹配，就会自动匹配这一行。并且后续就把包发给路由器，<code>Gateway</code> 即是路由器的 IP 地址。</p><blockquote><p>IP 报文生成</p></blockquote><p><img src="'+b+'" alt="IP 层报文"></p><h2 id="mac" tabindex="-1">MAC <a class="header-anchor" href="#mac" aria-label="Permalink to &quot;MAC&quot;">​</a></h2><p>生成了 IP 头部之后，接下来网络包还需要在 IP 头部的前面加上 <strong>MAC 头部</strong>。</p><blockquote><p>MAC包头格式</p></blockquote><p>在MAC包头中，包含了发送方和接收方的MAC地址和协议类型。</p><p>MAC 包头的<strong>协议类型</strong>只使用：</p><ul><li><code>0800</code> ： IP 协议</li><li><code>0806</code> ： ARP 协议</li></ul><p><img src="'+h+'" alt="MAC 包头格式"></p><blockquote><p>MAC 发送方和接收方如何确认?</p></blockquote><p><strong>发送方</strong>的 MAC 地址是在网卡生产时写入到 ROM 里的，只要将这个值读取出来写入到 MAC 头部就可以了。</p><p><strong>接收方</strong>的 MAC 地址就有点复杂了，只要告诉以太网对方的 MAC 的地址，以太网就会帮我们把包发送过去，那么很显然这里应该填写对方的 MAC 地址。</p><blockquote><p>如何获取对方的MAC地址</p></blockquote><p>需要 <code>ARP</code> 协议帮我们找到路由器的 MAC 地址。</p><p><img src="'+E+'" alt="ARP 广播"></p><p>ARP 协议会在以太网中以<strong>广播</strong>的形式，对以太网所有的设备喊出：“这个 IP 地址是谁的？请把你的 MAC 地址告诉我”。</p><p>然后就会有人回答：“这个 IP 地址是我的，我的 MAC 地址是 XXXX”。</p><p>如果对方和自己处于同一个子网中，那么通过上面的操作就可以得到对方的 MAC 地址。然后，我们将这个 MAC 地址写入 MAC 头部，MAC 头部就完成了。</p><p>在后续操作系统会把本次查询结果放到一块叫做 <strong>ARP 缓存</strong>的内存空间留着以后用，不过缓存的时间就几分钟。</p><p>也就是说，在发包时：</p><ul><li>先查询 ARP 缓存，如果其中已经保存了对方的 MAC 地址，就不需要发送 ARP 查询，直接使用 ARP 缓存中的地址。</li><li>而当 ARP 缓存中不存在对方 MAC 地址时，则发送 ARP 广播查询。</li></ul><blockquote><p>查询ARP缓存的内容</p></blockquote><p>在 Linux 系统中，使用 <code>arp -a</code> 命令</p><p><img src="'+k+'" alt="ARP 缓存内容"></p><blockquote><p>MAC 报文生成</p></blockquote><p><img src="'+M+'" alt="MAC 层报文"></p><h2 id="网卡" tabindex="-1">网卡 <a class="header-anchor" href="#网卡" aria-label="Permalink to &quot;网卡&quot;">​</a></h2><p>在前面的过程中，网络包还只是在内存中的一串二进制信息，没有办法直接发送给对方，因此我们需要<strong>将数字信息转换为电信号</strong>，这样数据才能在网线上传输。</p><p>网卡是负责这一动作的，要控制网卡还需要靠<strong>网卡驱动程序</strong>。</p><p>网卡驱动获取网络包之后，会将其<strong>复制</strong>到网卡内的缓存区中，接着会在其<strong>开头加上报头和起始帧分界符，在末尾加上用于检测错误的帧校验序列</strong>。</p><ul><li>起始帧分界符是一个用来表示包起始位置的标记</li><li>末尾的 <code>FCS</code>（帧校验序列）用来检查包传输过程是否有损坏</li></ul><p><img src="'+q+'" alt="数据包"></p><h2 id="交换机" tabindex="-1">交换机 <a class="header-anchor" href="#交换机" aria-label="Permalink to &quot;交换机&quot;">​</a></h2><p>交换机在接收到数据包后，会自动判断目标地址并将其转发到对应的端口，实现不同设备之间的通信。交换机内含有MAC地址表，其中主要包含两个信息：</p><ul><li>一个是设备的 MAC 地址，</li><li>另一个是该设备连接在交换机的哪个端口上。</li></ul><p><img src="'+I+'" alt="交换机的 MAC 地址表"></p><blockquote><p>如果 MAC 地址表找不到指定的 MAC 地址会怎么办？</p></blockquote><p>它会采用广播方式将数据包发送到<strong>所有连接的端口</strong>，除了源端口。这样做是为了确保数据包能够到达目的设备，即使交换机不知道具体哪个端口连接着该设备。通过广播，数据包会传达到局域网内的所有设备，而目的设备在接收到数据包后会进行响应。交换机就可以将它的地址写入 MAC 地址表，下次也就不需要把包发到所有端口了。</p><h2 id="路由器" tabindex="-1">路由器 <a class="header-anchor" href="#路由器" aria-label="Permalink to &quot;路由器&quot;">​</a></h2><p>路由器和交换机的不同：</p><ul><li><strong>路由器</strong>是基于 IP 设计的，俗称<strong>三层</strong>网络设备，路由器的各个端口都具有 MAC 地址和 IP 地址；</li><li>而<strong>交换机</strong>是基于以太网设计的，俗称<strong>二层</strong>网络设备，交换机的端口<strong>不具有</strong> MAC 地址。</li></ul><p>当转发包时，首先路由器端口会接收发给自己的以太网包，然后<strong>路由表</strong>查询转发目标，再由相应的端口作为发送方将以太网包发送出去。</p><blockquote><p>路由器的接收包操作</p></blockquote><p>电信号到达网线接口，将电信号转为数字信号，通过包末尾的<code>FCS</code>进行错误校验。如果没有错误，则检查MAC头部的<code>MAC</code>头部，看看是不是发给自己的包，如果是就放到接收缓冲区中，否则就丢弃这个包。</p><blockquote><p>查询路由表决定输出端口</p></blockquote><p>完成包接收操作之后，路由器就会<strong>去掉</strong>包开头的 MAC 头部。（<strong>MAC 头部的作用就是将包送达路由器</strong>，其中的接收方 MAC 地址就是路由器端口的 MAC 地址。因此，当包到达路由器之后，MAC 头部的任务就完成了，于是 MAC 头部就会<strong>被丢弃</strong>。）</p><p>路由器会根据 MAC 头部后方的 <code>IP</code> 头部中的内容进行包的转发操作。转发操作分为几个阶段，首先是查询<strong>路由表</strong>判断转发目标。</p><p><img src="'+S+'" alt="路由器转发"></p><blockquote><p>路由器的发送操作</p></blockquote><p>首先，我们需要根据<strong>路由表的网关列</strong>判断对方的地址。</p><ul><li>如果网关是一个 IP 地址，则这个IP 地址就是我们要转发到的目标地址，<strong>还未抵达终点</strong>，还需继续需要路由器转发。</li><li>如果网关为空，则 IP 头部中的接收方 IP 地址就是要转发到的目标地址，也是就终于找到 IP 包头里的目标地址了，说明<strong>已抵达终点</strong>。</li></ul><p>知道对方的ip地址了以后，通过<code>ARP</code>协议根据 IP 地址查询 MAC 地址，并将查询的结果作为接收方 MAC 地址。（路由器也有ARP缓存）</p><p>在网络包传输的过程中，<strong>源 IP 和目标 IP 始终是不会变的，一直变化的是 MAC 地址</strong>，因为需要 MAC 地址在以太网内进行<strong>两个设备</strong>之间的包传输。</p><h2 id="服务器解析" tabindex="-1">服务器解析 <a class="header-anchor" href="#服务器解析" aria-label="Permalink to &quot;服务器解析&quot;">​</a></h2><div style="display:none;" data-pagefind-meta="base64:JTdCJTIyZGF0ZSUyMiUzQTE3MTc1OTQxMTQxODQlN0Q="></div>',112),N=[B];function j(R,x,f,H,v,L){return t(),s("div",null,N)}const Y=o(D,[["render",j]]);export{w as __pageData,Y as default};
